// @ts-check
import { defineConfig } from "astro/config";
import tailwind from "@astrojs/tailwind";
import sitemap from "@astrojs/sitemap";

// https://docs.astro.build/en/reference/configuration-reference/
export default defineConfig({
  // ── Site URL ─────────────────────────────────────────────────────────────
  // Required for @astrojs/sitemap to generate correct URLs.
  // Also used for canonical link tags and og:url meta.
  site: "https://saralogy.com",

  // ── Output Mode ──────────────────────────────────────────────────────────
  // Static: zero server required. Perfect for a personal site on Vercel.
  // If SSR is ever needed (e.g. a dynamic contact form endpoint),
  // switch to output: "hybrid" and add @astrojs/vercel adapter.
  output: "static",

  // ── Integrations ─────────────────────────────────────────────────────────
  integrations: [
    tailwind({
      // Apply Tailwind base styles globally.
      // Set to false if you want to manage base styles yourself.
      applyBaseStyles: true,
    }),

    sitemap({
      // Filter out pages that should not appear in the sitemap.
      // Adjust as content sections are added.
      filter: (page) =>
        !page.includes("/404") && !page.includes("/draft/"),

      // Sitemap is automatically submitted to Google via Vercel's robots.txt.
      // Output: /sitemap-index.xml + /sitemap-0.xml (Astro standard)
      changefreq: "weekly",
      priority: 0.7,
      lastmod: new Date(),

      // Override priority for high-value pages
      customPages: [],
    }),
  ],

  // ── Image Optimization ───────────────────────────────────────────────────
  image: {
    // Use Astro's built-in Sharp-based image service for <Image /> components.
    // Images in /public are NOT processed — use /src/assets for processed images.
    service: {
      entrypoint: "astro/assets/services/sharp",
    },
    // Default image widths generated for responsive srcset
    // Covers: mobile (375), tablet (768), desktop (1200), retina (2x of each)
    remotePatterns: [
      // Add any external image domains here if you embed images from CDNs
      // { protocol: "https", hostname: "**.your-cdn.com" },
    ],
  },

  // ── Build Configuration ──────────────────────────────────────────────────
  build: {
    // Inline stylesheets smaller than 4KB into <style> tags (fewer requests)
    inlineStylesheets: "auto",

    // Keep output filenames human-readable for debugging
    // Astro appends content hashes automatically
    assets: "_astro",
  },

  // ── Prefetch ─────────────────────────────────────────────────────────────
  // Prefetch links on hover for snappier navigation on internal pages.
  prefetch: {
    prefetchAll: false, // Only prefetch links with data-astro-prefetch attribute
    defaultStrategy: "hover",
  },

  // ── Dev Server ───────────────────────────────────────────────────────────
  server: {
    port: 4321,
    host: false, // Only listen on localhost in dev
  },

  // ── Vite Configuration ───────────────────────────────────────────────────
  vite: {
    build: {
      // Warn (not fail) if a JS chunk exceeds 100KB.
      // CI performance budget check will flag these as warnings.
      chunkSizeWarningLimit: 100,

      rollupOptions: {
        output: {
          // Manual chunk splitting: keep vendor libs separate from app code
          // so user code cache invalidation doesn't bust vendor cache.
          manualChunks: (id) => {
            if (id.includes("node_modules")) {
              return "vendor";
            }
          },
        },
      },
    },
  },
});

{
  "$schema": "https://openapi.vercel.sh/vercel.json",
  "framework": "astro",
  "buildCommand": "bunx astro build",
  "outputDirectory": "dist",
  "installCommand": "bun install",
  "devCommand": "bunx astro dev",

  "cleanUrls": true,
  "trailingSlash": false,

  "redirects": [
    {
      "source": "https://www.saralogy.com/(.*)",
      "destination": "https://saralogy.com/$1",
      "permanent": true
    },
    {
      "source": "/home",
      "destination": "/",
      "permanent": true
    },
    {
      "source": "/blog/:slug",
      "destination": "/writing/:slug",
      "permanent": true
    }
  ],

  "headers": [
    {
      "source": "/(.*)",
      "headers": [
        {
          "key": "X-Frame-Options",
          "value": "SAMEORIGIN"
        },
        {
          "key": "X-Content-Type-Options",
          "value": "nosniff"
        },
        {
          "key": "Referrer-Policy",
          "value": "strict-origin-when-cross-origin"
        },
        {
          "key": "Permissions-Policy",
          "value": "camera=(), microphone=(), geolocation=(), browsing-topics=()"
        },
        {
          "key": "X-DNS-Prefetch-Control",
          "value": "on"
        },
        {
          "key": "Strict-Transport-Security",
          "value": "max-age=63072000; includeSubDomains; preload"
        }
      ]
    },
    {
      "source": "/_astro/(.*)",
      "headers": [
        {
          "key": "Cache-Control",
          "value": "public, max-age=31536000, immutable"
        }
      ]
    },
    {
      "source": "/fonts/(.*)",
      "headers": [
        {
          "key": "Cache-Control",
          "value": "public, max-age=31536000, immutable"
        }
      ]
    },
    {
      "source": "/images/(.*)",
      "headers": [
        {
          "key": "Cache-Control",
          "value": "public, max-age=86400, stale-while-revalidate=604800"
        }
      ]
    },
    {
      "source": "/sitemap(.*).xml",
      "headers": [
        {
          "key": "Cache-Control",
          "value": "public, max-age=3600, stale-while-revalidate=86400"
        }
      ]
    }
  ],

  "rewrites": [
    {
      "source": "/404",
      "destination": "/404.html"
    }
  ],

  "env": {
    "SITE_URL": "https://saralogy.com",
    "PUBLIC_SITE_NAME": "saralogy.com",
    "PUBLIC_SITE_DESCRIPTION": "AI-native marketing for DACH SMEs"
  }
}

